/**
 * @module Utils/CopyTestReports
 * @description Copies test reports and coverage data to the docs/ directory
 * for inclusion in the documentation bundle. Generates comprehensive HTML
 * index pages for test results with links to all available reports.
 */

import { promises as fs } from 'fs';
import { join, resolve } from 'path';
import { pathToFileURL } from 'url';
import { PROJECT_ROOT } from '../constants/config.js';

const DOCS_DIR = join(PROJECT_ROOT, 'docs');
const BUILDS_DIR = join(PROJECT_ROOT, 'builds');

/**
 * Recursively copy directory
 *
 * @param src - Source directory
 * @param dest - Destination directory
 */
export async function copyDirectory(src: string, dest: string): Promise<void> {
  try {
    await fs.mkdir(dest, { recursive: true });

    const entries = await fs.readdir(src, { withFileTypes: true });

    for (const entry of entries) {
      const srcPath = join(src, entry.name);
      const destPath = join(dest, entry.name);

      if (entry.isDirectory()) {
        await copyDirectory(srcPath, destPath);
      } else {
        await fs.copyFile(srcPath, destPath);
      }
    }
  } catch (error) {
    const nodeError = error as NodeJS.ErrnoException;
    if (nodeError.code === 'ENOENT') {
      console.warn(`  ⚠️  Source directory not found (skipped): ${src}`);
    } else {
      throw error;
    }
  }
}

/**
 * Copy a single file safely
 *
 * @param src - Source file path
 * @param dest - Destination file path
 * @returns Whether the copy succeeded
 */
async function copyFileSafe(src: string, dest: string): Promise<boolean> {
  try {
    await fs.copyFile(src, dest);
    return true;
  } catch {
    return false;
  }
}

/**
 * Check if a file or directory exists
 *
 * @param path - Path to check
 * @returns Whether the path exists
 */
async function pathExists(path: string): Promise<boolean> {
  try {
    await fs.access(path);
    return true;
  } catch {
    return false;
  }
}

/**
 * Gather report availability info for index generation
 *
 * @returns Object describing which reports are available
 */
async function gatherReportInfo(): Promise<{
  hasVitestHtml: boolean;
  hasVitestJson: boolean;
  hasVitestJunit: boolean;
  hasE2eJson: boolean;
  hasE2eJunit: boolean;
  hasEslintHtml: boolean;
  hasEslintJson: boolean;
  hasCoverage: boolean;
  hasPlaywright: boolean;
  vitestSummary: { tests: number; passed: number; failed: number; duration: number } | null;
  e2eSummary: { tests: number; passed: number; failed: number } | null;
}> {
  const testResultsDir = join(DOCS_DIR, 'test-results');
  const info = {
    hasVitestHtml: await pathExists(join(testResultsDir, 'html', 'index.html')),
    hasVitestJson: await pathExists(join(testResultsDir, 'results.json')),
    hasVitestJunit: await pathExists(join(testResultsDir, 'junit.xml')),
    hasE2eJson: await pathExists(join(testResultsDir, 'e2e-results.json')),
    hasE2eJunit: await pathExists(join(testResultsDir, 'e2e-junit.xml')),
    hasEslintHtml: await pathExists(join(testResultsDir, 'eslint-report.html')),
    hasEslintJson: await pathExists(join(testResultsDir, 'eslint-report.json')),
    hasCoverage: await pathExists(join(DOCS_DIR, 'coverage', 'index.html')),
    hasPlaywright: await pathExists(join(DOCS_DIR, 'playwright-report', 'index.html')),
    vitestSummary: null as { tests: number; passed: number; failed: number; duration: number } | null,
    e2eSummary: null as { tests: number; passed: number; failed: number } | null,
  };

  // Try to parse vitest JSON results for summary
  if (info.hasVitestJson) {
    try {
      const raw = await fs.readFile(join(testResultsDir, 'results.json'), 'utf8');
      const data = JSON.parse(raw) as {
        numTotalTests?: number;
        numPassedTests?: number;
        numFailedTests?: number;
        testResults?: Array<{ numPassingTests?: number; numFailingTests?: number; perfStats?: { end?: number; start?: number } }>;
      };
      const total = data.numTotalTests ?? 0;
      const passed = data.numPassedTests ?? 0;
      const failed = data.numFailedTests ?? 0;
      let duration = 0;
      if (Array.isArray(data.testResults)) {
        for (const r of data.testResults) {
          if (r.perfStats?.end && r.perfStats?.start) {
            duration += r.perfStats.end - r.perfStats.start;
          }
        }
      }
      info.vitestSummary = { tests: total, passed, failed, duration: Math.round(duration) };
    } catch {
      // Ignore parse errors
    }
  }

  // Try to parse E2E JSON results for summary
  if (info.hasE2eJson) {
    try {
      const raw = await fs.readFile(join(testResultsDir, 'e2e-results.json'), 'utf8');
      const data = JSON.parse(raw) as {
        stats?: { expected?: number; unexpected?: number; flaky?: number; skipped?: number };
      };
      if (data.stats) {
        const passed = data.stats.expected ?? 0;
        const failed = data.stats.unexpected ?? 0;
        const flaky = data.stats.flaky ?? 0;
        info.e2eSummary = { tests: passed + failed + flaky, passed, failed };
      }
    } catch {
      // Ignore parse errors
    }
  }

  return info;
}

/**
 * Create a comprehensive HTML index for test results
 *
 * @param info - Report availability information
 * @returns HTML content
 */
function createTestResultsIndex(info: Awaited<ReturnType<typeof gatherReportInfo>>): string {
  const currentDate = new Date().toISOString().split('T')[0]!;

  const vitestStats = info.vitestSummary
    ? `<div class="stat-card passed">
        <div class="stat-number">${info.vitestSummary.passed}</div>
        <div class="stat-label">Passed</div>
      </div>
      <div class="stat-card ${info.vitestSummary.failed > 0 ? 'failed' : 'passed'}">
        <div class="stat-number">${info.vitestSummary.failed}</div>
        <div class="stat-label">Failed</div>
      </div>
      <div class="stat-card">
        <div class="stat-number">${info.vitestSummary.tests}</div>
        <div class="stat-label">Total Tests</div>
      </div>
      <div class="stat-card">
        <div class="stat-number">${(info.vitestSummary.duration / 1000).toFixed(1)}s</div>
        <div class="stat-label">Duration</div>
      </div>`
    : '';

  const e2eStats = info.e2eSummary
    ? `<div class="stat-card passed">
        <div class="stat-number">${info.e2eSummary.passed}</div>
        <div class="stat-label">Passed</div>
      </div>
      <div class="stat-card ${info.e2eSummary.failed > 0 ? 'failed' : 'passed'}">
        <div class="stat-number">${info.e2eSummary.failed}</div>
        <div class="stat-label">Failed</div>
      </div>
      <div class="stat-card">
        <div class="stat-number">${info.e2eSummary.tests}</div>
        <div class="stat-label">Total E2E</div>
      </div>`
    : '';

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <meta name="description" content="EU Parliament Monitor - Comprehensive Test Results and Quality Reports">
  <title>Test Results - EU Parliament Monitor</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
      line-height: 1.6;
      color: #333;
      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
      min-height: 100vh;
      padding: 2rem;
    }
    .container {
      max-width: 1200px;
